 17→
 18→import android.content.Context
 19→import android.graphics.Bitmap
 20→import android.graphics.BitmapFactory
 21→import android.net.Uri
 22→import androidx.annotation.CheckResult
 23→import com.ichi2.anki.UIUtils.showThemedToast
 24→import com.ichi2.anki.multimediacard.fields.ImageField
 25→import com.ichi2.compat.CompatHelper
 26→import com.ichi2.libanki.exception.EmptyMediaException
 27→import com.ichi2.utils.ContentResolverUtil.getFileName
 28→import com.ichi2.utils.FileUtil.getFileNameAndExtension
 29→import timber.log.Timber
 30→import java.io.*
 31→
 32→/**
 33→ * RegisterMediaForWebView is used for registering media in temp path,
 34→ * this class is required in summer note class for paste image event and in visual editor activity for importing media,
 35→ * (extracted code to avoid duplication of code).
 36→ */
 37→class MediaRegistration(private val context: Context) {
 38→    // Use the same HTML if the same image is pasted multiple times.
 39→    private val pastedImageCache = HashMap<String, String?>()
 40→
 41→    /**
 42→     * Loads an image into the collection.media directory and returns a HTML reference
 43→     * @param uri The uri of the image to load
 44→     * @return HTML referring to the loaded image
 45→     */
 46→    @Throws(IOException::class)
 47→    fun loadImageIntoCollection(uri: Uri): String? {
 48→        val fileName: String
 49→        val filename = getFileName(context.contentResolver, uri)
 50→        val fd = openInputStreamWithURI(uri)
 51→        val fileNameAndExtension = getFileNameAndExtension(filename)
 52→        fileName = if (checkFilename(fileNameAndExtension!!)) {
 53→            "${fileNameAndExtension.key}-name"
 54→        } else {
 55→            fileNameAndExtension.key
 56→        }
 57→        var clipCopy: File
 58→        var bytesWritten: Long
 59→        openInputStreamWithURI(uri).use { copyFd ->
 60→            // no conversion to jpg in cases of gif and jpg and if png image with alpha channel
 61→            if (shouldConvertToJPG(fileNameAndExtension.value, copyFd)) {
 62→                clipCopy = File.createTempFile(fileName, ".jpg")
 63→                bytesWritten = CompatHelper.compat.copyFile(fd, clipCopy.absolutePath)
 64→                // return null if jpg conversion false.
 65→                if (!convertToJPG(clipCopy)) {
 66→                    return null
 67→                }
 68→            } else {
 69→                clipCopy = File.createTempFile(fileName, fileNameAndExtension.value)
 70→                bytesWritten = CompatHelper.compat.copyFile(fd, clipCopy.absolutePath)
 71→            }
 72→        }
 73→        val tempFilePath = clipCopy.absolutePath
 74→        // register media for webView
 75→        if (!registerMediaForWebView(tempFilePath)) {
 76→            return null
 77→        }
 78→        Timber.d("File was %d bytes", bytesWritten)
 79→        if (bytesWritten > MEDIA_MAX_SIZE) {
 80→            Timber.w("File was too large: %d bytes", bytesWritten)
 81→            showThemedToast(context, context.getString(R.string.note_editor_paste_too_large), false)
 82→            File(tempFilePath).delete()
 83→            return null
 84→        }
 85→        val field = ImageField()
 86→        field.hasTemporaryMedia = true
 87→        field.extraImagePathRef = tempFilePath
 88→        return field.formattedValue
 89→    }
 90→
 91→    @Throws(FileNotFoundException::class)
 92→    private fun openInputStreamWithURI(uri: Uri): InputStream {
 93→        return context.contentResolver.openInputStream(uri)!!
 94→    }
 95→
 96→    private fun convertToJPG(file: File): Boolean {
 97→        val bm = BitmapFactory.decodeFile(file.absolutePath)
 98→        try {
 99→            FileOutputStream(file.absolutePath).use { outStream ->
100→                bm.compress(Bitmap.CompressFormat.JPEG, 100, outStream)
101→                outStream.flush()
102→            }
103→        } catch (e: IOException) {
104→            Timber.w("MediaRegistration : Unable to convert file to png format")
105→            CrashReportService.sendExceptionReport(e, "Unable to convert file to png format")
106→            showThemedToast(context, context.resources.getString(R.string.multimedia_editor_png_paste_error, e.message), true)
107→            return false
108→        }
109→        return true // successful conversion to jpg.
110→    }
111→
112→    private fun shouldConvertToJPG(fileNameExtension: String, fileStream: InputStream): Boolean {
113→        if (".jpg" == fileNameExtension) {
114→            return false // we are already a jpg, no conversion
115→        }
116→        if (".gif" == fileNameExtension) {
117→            return false // gifs may have animation, conversion would ruin them
118→        }
119→        if (".png" == fileNameExtension && doesInputStreamContainTransparency(fileStream)) {
120→            return false // pngs with transparency would be ruined by conversion
121→        }
122→        return true
123→    }
124→
125→    private fun checkFilename(fileNameAndExtension: Map.Entry<String, String>): Boolean {
126→        return fileNameAndExtension.key.length <= 3
127→    }
128→
129→    fun onImagePaste(uri: Uri): String? {
130→        return try {
131→            // check if cache already holds registered file or not
132→            if (!pastedImageCache.containsKey(uri.toString())) {
133→                pastedImageCache[uri.toString()] = loadImageIntoCollection(uri)
134→            }
135→            pastedImageCache[uri.toString()]
136→        } catch (ex: NullPointerException) {
137→            // Tested under FB Messenger and GMail, both apps do nothing if this occurs.
138→            // This typically works if the user copies again - don't know the exact cause
139→
140→            //  java.lang.SecurityException: Permission Denial: opening provider
141→            //  org.chromium.chrome.browser.util.ChromeFileProvider from ProcessRecord{80125c 11262:com.ichi2.anki/u0a455}
142→            //  (pid=11262, uid=10455) that is not exported from UID 10057
143→            Timber.w(ex, "Failed to paste image")
144→            null
145→        } catch (ex: SecurityException) {
146→            Timber.w(ex, "Failed to paste image")
147→            null
148→        } catch (e: Exception) {
149→            // NOTE: This is happy path coding which works on Android 9.
150→            CrashReportService.sendExceptionReport("File is invalid issue:8880", "RegisterMediaForWebView:onImagePaste URI of file:$uri")
151→            Timber.w(e, "Failed to paste image")
152→            showThemedToast(context, context.getString(R.string.multimedia_editor_something_wrong), false)
153→            null
154→        }
155→    }
156→
157→    @CheckResult
158→    fun registerMediaForWebView(imagePath: String?): Boolean {
159→        if (imagePath == null) {
160→            // Nothing to register - continue with execution.
161→            return true
162→        }
163→        Timber.i("Adding media to collection: %s", imagePath)
164→        val f = File(imagePath)
165→        return try {
166→            CollectionHelper.instance.getColUnsafe(context)!!.media.addFile(f)
167→            true
168→        } catch (e: IOException) {
169→            Timber.w(e, "Failed to add file")
170→            false
171→        } catch (e: EmptyMediaException) {
172→            Timber.w(e, "Failed to add file")
173→            false
174→        }
175→    }
176→
177→    companion object {
178→        private const val MEDIA_MAX_SIZE = 5 * 1000 * 1000
179→        private const val COLOR_GREY = 0
180→        private const val COLOR_TRUE = 2
181→        private const val COLOR_INDEX = 3
182→        private const val COLOR_GREY_ALPHA = 4
183→        private const val COLOR_TRUE_ALPHA = 6
184→
185→        /**
186→         * given an inputStream of a file,
187→         * returns true if found that it has transparency (in its header)
188→         * code: https://stackoverflow.com/a/31311718/14148406
189→         */
190→        private fun doesInputStreamContainTransparency(inputStream: InputStream): Boolean {
191→            try {
192→                // skip: png signature,header chunk declaration,width,height,bitDepth :
193→                inputStream.skip((12 + 4 + 4 + 4 + 1).toLong())
194→                when (inputStream.read()) {
195→                    COLOR_GREY_ALPHA, COLOR_TRUE_ALPHA -> return true
196→                    COLOR_INDEX, COLOR_GREY, COLOR_TRUE -> return false
197→                }
198→                return true
199→            } catch (e: Exception) {
200→                Timber.w(e, "Failed to check transparency of inputStream")
201→            }
202→            return false
203→        }
204→    }
205→}
