165→    var typedElement = document.getElementsByName("typed")[0];
166→
167→    _runHook(onUpdateHook)
168→        .then(() => {
169→            if (window.MathJax != null) {
170→                /* Anki-Android adds mathjax-needs-to-render" as a class to the card when
171→                   it detects both \( and \) or \[ and \].
172→
173→                   This does not control *loading* MathJax, but rather controls whether or not MathJax
174→                   renders content.  We hide all the content until MathJax renders, because otherwise
175→                   the content loads, and has to reflow after MathJax renders, and it's unsightly.
176→                   However, if we hide all the content every time, folks don't like the repainting after
177→                   every question or answer.  This is a middle-ground, where there is no repainting due to
178→                   MathJax on non-MathJax cards, and on MathJax cards, there is a small flicker, but there's
179→                   no reflowing because the content only shows after MathJax has rendered. */
180→
181→                if (card.classList.contains("mathjax-needs-to-render")) {
182→                    return MathJax.startup.promise
183→                        .then(() => MathJax.typesetPromise([card]))
184→                        .then(() => card.classList.remove("mathjax-needs-to-render"));
185→                }
