 45→     */
 46→    @Throws(IOException::class)
 47→    fun loadImageIntoCollection(uri: Uri): String? {
 48→        val fileName: String
 49→        val filename = getFileName(context.contentResolver, uri)
 50→        val fd = openInputStreamWithURI(uri)
 51→        val fileNameAndExtension = getFileNameAndExtension(filename)
 52→        fileName = if (checkFilename(fileNameAndExtension!!)) {
 53→            "${fileNameAndExtension.key}-name"
 54→        } else {
 55→            fileNameAndExtension.key
 56→        }
 57→        var clipCopy: File
 58→        var bytesWritten: Long
 59→        openInputStreamWithURI(uri).use { copyFd ->
 60→            // no conversion to jpg in cases of gif and jpg and if png image with alpha channel
 61→            if (shouldConvertToJPG(fileNameAndExtension.value, copyFd)) {
 62→                clipCopy = File.createTempFile(fileName, ".jpg")
 63→                bytesWritten = CompatHelper.compat.copyFile(fd, clipCopy.absolutePath)
 64→                // return null if jpg conversion false.
 65→                if (!convertToJPG(clipCopy)) {
 66→                    return null
 67→                }
 68→            } else {
 69→                clipCopy = File.createTempFile(fileName, fileNameAndExtension.value)
 70→                bytesWritten = CompatHelper.compat.copyFile(fd, clipCopy.absolutePath)
 71→            }
 72→        }
 73→        val tempFilePath = clipCopy.absolutePath
 74→        // register media for webView
 75→        if (!registerMediaForWebView(tempFilePath)) {
 76→            return null
 77→        }
 78→        Timber.d("File was %d bytes", bytesWritten)
 79→        if (bytesWritten > MEDIA_MAX_SIZE) {
 80→            Timber.w("File was too large: %d bytes", bytesWritten)
 81→            showThemedToast(context, context.getString(R.string.note_editor_paste_too_large), false)
 82→            File(tempFilePath).delete()
 83→            return null
 84→        }
 85→        val field = ImageField()
 86→        field.hasTemporaryMedia = true
 87→        field.extraImagePathRef = tempFilePath
 88→        return field.formattedValue
 89→    }
