 96→    private fun convertToJPG(file: File): Boolean {
 97→        val bm = BitmapFactory.decodeFile(file.absolutePath)
 98→        try {
 99→            FileOutputStream(file.absolutePath).use { outStream ->
100→                bm.compress(Bitmap.CompressFormat.JPEG, 100, outStream)
101→                outStream.flush()
102→            }
103→        } catch (e: IOException) {
104→            Timber.w("MediaRegistration : Unable to convert file to png format")
105→            CrashReportService.sendExceptionReport(e, "Unable to convert file to png format")
106→            showThemedToast(context, context.resources.getString(R.string.multimedia_editor_png_paste_error, e.message), true)
107→            return false
108→        }
109→        return true // successful conversion to jpg.
110→    }
111→
112→    private fun shouldConvertToJPG(fileNameExtension: String, fileStream: InputStream): Boolean {
113→        if (".jpg" == fileNameExtension) {
114→            return false // we are already a jpg, no conversion
115→        }
116→        if (".gif" == fileNameExtension) {
117→            return false // gifs may have animation, conversion would ruin them
118→        }
119→        if (".png" == fileNameExtension && doesInputStreamContainTransparency(fileStream)) {
120→            return false // pngs with transparency would be ruined by conversion
121→        }
122→        return true
123→    }
124→
125→    private fun checkFilename(fileNameAndExtension: Map.Entry<String, String>): Boolean {
126→        return fileNameAndExtension.key.length <= 3
127→    }
