177→    companion object {
178→        private const val MEDIA_MAX_SIZE = 5 * 1000 * 1000
179→        private const val COLOR_GREY = 0
180→        private const val COLOR_TRUE = 2
181→        private const val COLOR_INDEX = 3
182→        private const val COLOR_GREY_ALPHA = 4
183→        private const val COLOR_TRUE_ALPHA = 6
184→
185→        /**
186→         * given an inputStream of a file,
187→         * returns true if found that it has transparency (in its header)
188→         * code: https://stackoverflow.com/a/31311718/14148406
189→         */
190→        private fun doesInputStreamContainTransparency(inputStream: InputStream): Boolean {
191→            try {
192→                // skip: png signature,header chunk declaration,width,height,bitDepth :
193→                inputStream.skip((12 + 4 + 4 + 4 + 1).toLong())
194→                when (inputStream.read()) {
195→                    COLOR_GREY_ALPHA, COLOR_TRUE_ALPHA -> return true
196→                    COLOR_INDEX, COLOR_GREY, COLOR_TRUE -> return false
197→                }
198→                return true
199→            } catch (e: Exception) {
200→                Timber.w(e, "Failed to check transparency of inputStream")
201→            }
202→            return false
203→        }
204→    }
205→}
